import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import axios from 'axios';
import './App.css';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import BlogList from './components/BlogList';
import BlogDetail from './components/BlogDetail';
import CreateBlog from './components/CreateBlog';
import EditBlog from './components/EditBlog';

const API_URL = 'http://localhost:5000/api/posts';

function App() {
  const [blogs, setBlogs] = useState([]);
  const [topics, setTopics] = useState([]);
  const [selectedTopicId, setSelectedTopicId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const fetchTopics = async () => {
    try {
      const response = await axios.get(`${API_URL.replace('/posts', '')}/topics`);
      setTopics(response.data);
    } catch (err) {
      console.error('Error fetching topics:', err);
      setTopics(['OS', 'Multithreading', 'Linux', 'Networking', 'Databases', 'Other']);
    }
  };

  const fetchBlogs = async () => {
    setLoading(true);
    try {
      const response = await axios.get(API_URL);
      setBlogs(response.data);
      setError(null);
    } catch (err) {
      setError('Failed to fetch blogs');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTopics();
    fetchBlogs();
  }, []);

  const handleCreate = async (newBlog) => {
    try {
      const response = await axios.post(API_URL, newBlog);
      setBlogs([...blogs, response.data]);
    } catch (err) {
      setError('Failed to create blog');
      console.error(err);
    }
  };

  const handleUpdate = async (id, updatedBlog) => {
    try {
      const response = await axios.put(`${API_URL}/${id}`, updatedBlog);
      setBlogs(blogs.map(blog => blog.id === id ? response.data : blog));
    } catch (err) {
      setError('Failed to update blog');
      console.error(err);
    }
  };

  const handleDelete = async (id) => {
    try {
      await axios.delete(`${API_URL}/${id}`);
      setBlogs(blogs.filter(blog => blog.id !== id));
    } catch (err) {
      setError('Failed to delete blog');
      console.error(err);
    }
  };

  return (
    <Router>
      <div className="App">
        <Header />
        {error && <div className="error-message">{error}</div>}
        <div className="content-layout">
          <Sidebar
            blogs={blogs}
            loading={loading}
            topics={topics}
            selectedTopicId={selectedTopicId}
            onTopicSelect={setSelectedTopicId}
            onTopicsChange={setTopics}
          />
          <main className="main-content">
            <Routes>
              <Route 
                path="/" 
                element={<BlogList blogs={blogs} loading={loading} selectedTopicId={selectedTopicId} />} 
              />
              <Route 
                path="/blog/:id" 
                element={<BlogDetail blogs={blogs} onDelete={handleDelete} />} 
              />
              <Route 
                path="/create" 
                element={<CreateBlog onCreate={handleCreate} topics={topics} />} 
              />
              <Route 
                path="/edit/:id" 
                element={<EditBlog blogs={blogs} onUpdate={handleUpdate} topics={topics} />} 
              />
            </Routes>
          </main>
        </div>
      </div>
    </Router>
  );
}

export default App;
